import django
from django.conf import settings
settings.configure(
    DATABASES={
        'default': {
            'ENGINE': 'django.db.backends.sqlite3',
            'NAME': ':memory:',
        }
    },
    INSTALLED_APPS=['django.contrib.contenttypes', 'django.contrib.auth'],
)
django.setup()

from django.db import connection
from django.db.models.sql.compiler import SQLCompiler
from django.db.models.expressions import ColPairs
from django.db.models import Value, F
from django.db.models.functions import Concat
from django.contrib.auth.models import User

# Monkey-patch get_select to apply the fix
original_get_select = SQLCompiler.get_select

def patched_get_select(self, with_col_aliases=False):
    from django.db.models.expressions import RawSQL, ColPairs, Value
    select = []
    klass_info = None
    annotations = {}
    assert not (self.query.select and self.query.default_cols)
    select_mask = self.query.get_select_mask()
    if self.query.default_cols:
        cols = self.get_default_columns(select_mask)
    else:
        cols = self.query.select
    if cols:
        klass_info = {
            'model': self.query.model,
            'select_fields': list(
                range(
                    len(self.query.extra_select),
                    len(self.query.extra_select) + len(cols),
                )
            ),
        }
    selected = []
    if self.query.selected is None:
        selected = [
            *(
                (alias, RawSQL(*args))
                for alias, args in self.query.extra_select.items()
            ),
            *((None, col) for col in cols),
            *self.query.annotation_select.items(),
        ]
    else:
        # FIX: track actual positions of column references
        select_fields = []
        for idx, (alias, expression) in enumerate(self.query.selected.items()):
            if isinstance(expression, str):
                expression = self.query.annotations[expression]
            elif isinstance(expression, int):
                expression = cols[expression]
                select_fields.append(idx)  # <-- track actual position
            if isinstance(expression, ColPairs):
                alias = None
            selected.append((alias, expression))
        if klass_info is not None:
            klass_info['select_fields'] = select_fields  # <-- update klass_info

    for select_idx, (alias, expression) in enumerate(selected):
        if alias:
            annotations[alias] = select_idx
        select.append((expression, alias))

    if self.query.select_related:
        related_klass_infos = self.get_related_selections(select, select_mask)
        klass_info['related_klass_infos'] = related_klass_infos

        def get_select_from_parent(klass_info):
            for ki in klass_info['related_klass_infos']:
                if ki['from_parent']:
                    ki['select_fields'] = (
                        klass_info['select_fields'] + ki['select_fields']
                    )
                get_select_from_parent(ki)

        get_select_from_parent(klass_info)

    from django.core.exceptions import EmptyResultSet, FullResultSet
    ret = []
    col_idx = 1
    for col, alias in select:
        try:
            sql, params = self.compile(col)
        except EmptyResultSet:
            empty_result_set_value = getattr(col, 'empty_result_set_value', NotImplemented)
            if empty_result_set_value is NotImplemented:
                sql, params = '0', ()
            else:
                sql, params = self.compile(Value(empty_result_set_value))
        except FullResultSet:
            sql, params = self.compile(Value(True))
        else:
            sql, params = col.select_format(self, sql, params)
        if alias is None and with_col_aliases:
            alias = f'col{col_idx}'
            col_idx += 1
        ret.append((col, (sql, params), alias))
    return ret, klass_info, annotations

SQLCompiler.get_select = patched_get_select

# Create a query that mimics the bug scenario
qs = User.objects.select_for_update(of=('self',)).values_list(
    Concat(Value('Dr. '), F('username')), 'id'
)

# Compile the query
compiler = qs.query.get_compiler(using='default')
compiler.setup_query()

print('self.select:')
for i, item in enumerate(compiler.select):
    print(f'  [{i}]: {item[0]!r}')
print()
print('klass_info select_fields:', compiler.klass_info['select_fields'])
print()

# Now call get_select_for_update_of_arguments() - should NOT raise AttributeError
try:
    result = compiler.get_select_for_update_of_arguments()
    print('Result (no crash!):', result)
except AttributeError as e:
    print('AttributeError:', e)
    import traceback
    traceback.print_exc()
